### Encrypt and Decrypt Sessions with Jose in Next.js

Source: https://github.com/vercel/next.js/blob/canary/docs/01-app/02-guides/authentication.mdx

Implements JWT-based session encryption and decryption using the Jose library with HS256 algorithm. The encrypt function creates a signed JWT with a 7-day expiration, while the decrypt function verifies and extracts the payload. Uses the server-only package to ensure operations execute only on the server, compatible with Next.js Edge Runtime.

```typescript
import 'server-only'
import { SignJWT, jwtVerify } from 'jose'
import { SessionPayload } from '@/app/lib/definitions'

const secretKey = process.env.SESSION_SECRET
const encodedKey = new TextEncoder().encode(secretKey)

export async function encrypt(payload: SessionPayload) {
  return new SignJWT(payload)
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime('7d')
    .sign(encodedKey)
}

export async function decrypt(session: string | undefined = '') {
  try {
    const { payload } = await jwtVerify(session, encodedKey, {
      algorithms: ['HS256'],
    })
    return payload
  } catch (error) {
    console.log('Failed to verify session')
  }
}
```

